prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId WHERE {
  VALUES ?id {"5ee15f85aeb74d8d9e31df0e41fea6fe"}
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(?origId = "5ee15f85aeb74d8d9e31df0e41fea6fe" || ?normId = "5ee15f85aeb74d8d9e31df0e41fea6fe")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?end ?endName ?between ?betweenName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "5ee15f85aeb74d8d9e31df0e41fea6fe" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  { ?start a bboExt:ChoreographyTask ; bbo:name ?startName . }
  UNION
  { ?start a bboExt:Message ; bbo:name ?startName . }

  FILTER(
    CONTAINS(LCASE(STR(?startName)), LCASE("estimate")) &&
    CONTAINS(LCASE(STR(?startName)), LCASE("cost"))
  )

  { ?end a bboExt:ChoreographyTask ; bbo:name ?endName . }
  UNION
  { ?end a bboExt:Message ; bbo:name ?endName . }
  FILTER(
    CONTAINS(LCASE(STR(?endName)), LCASE("send")) &&
    CONTAINS(LCASE(STR(?endName)), LCASE("receipt"))
    || CONTAINS(LCASE(STR(?endName)), LCASE("receipt"))
  )

  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?between .
  ?between ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .

  ?between a bboExt:ChoreographyTask .
  OPTIONAL { ?between bbo:name ?betweenName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?between ?betweenName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "5ee15f85aeb74d8d9e31df0e41fea6fe" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?start a bboExt:ChoreographyTask ;
         bbo:name ?startName .
  FILTER(
    CONTAINS(LCASE(STR(?startName)), LCASE("estimate")) &&
    CONTAINS(LCASE(STR(?startName)), LCASE("insurance")) &&
    CONTAINS(LCASE(STR(?startName)), LCASE("cost"))
  )

  ?end a bboExt:ChoreographyTask ;
       bbo:name ?endName .
  FILTER(
    CONTAINS(LCASE(STR(?endName)), LCASE("send")) &&
    CONTAINS(LCASE(STR(?endName)), LCASE("receipt"))
  )

  # between is one sequence-flow step after start
  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?start ;
        bbo:has_targetRef ?between .

  ?between a bboExt:ChoreographyTask ;
            bbo:name ?betweenName .

  # but between can (possibly through multiple steps) reach end
  ?between ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .
}
LIMIT 25
